const childWorkflows = ['CWF-610', 'CWF-620', 'CWF-630'];
let executionPlan = { workflows_to_execute: childWorkflows, current_index: 0, status: 'PLANNING', async_collection_allowed: true, loop_closure_required: true };
return [{ json: { ...$json, execution_plan: executionPlan, pack_orchestration: { started_at: new Date().toISOString(), expected_duration_seconds: 180 } } }];

// Capture cwf610_result after sub-workflow CWF-610
const subOutput = $json || {};
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}
const acc = { ...parentCtx };

acc["cwf610_result"] = {
  status: subOutput.status || 'SUCCESS',
  payload: subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};
return [{ json: acc }];

// Capture cwf620_result after sub-workflow CWF-620
const subOutput = $json || {};
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}
const acc = { ...parentCtx };
try { const c = $('Capture CWF-610 Result').first(); if (c) acc["cwf610_result"] = c.json["cwf610_result"] || c.json; } catch(e) {}
acc["cwf620_result"] = {
  status: subOutput.status || 'SUCCESS',
  payload: subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};
return [{ json: acc }];

// Capture cwf630_result after sub-workflow CWF-630
const subOutput = $json || {};
let parentCtx = {};
try { parentCtx = $('Execution Planner Node').first().json || {}; } catch(e) {}
const acc = { ...parentCtx };
try { const c = $('Capture CWF-610 Result').first(); if (c) acc["cwf610_result"] = c.json["cwf610_result"] || c.json; } catch(e) {}
  try { const c = $('Capture CWF-620 Result').first(); if (c) acc["cwf620_result"] = c.json["cwf620_result"] || c.json; } catch(e) {}
acc["cwf630_result"] = {
  status: subOutput.status || 'SUCCESS',
  payload: subOutput.payload || subOutput,
  captured_at: new Date().toISOString()
};
return [{ json: acc }];

// Phase-2 chain validation: pass if all children returned SUCCESS/COMPLETED.
const childResults = {
  CWF_610: $json.cwf610_result,
  CWF_620: $json.cwf620_result,
  CWF_630: $json.cwf630_result
};
const allHealthy = Object.values(childResults).every(r => r && (r.status === 'SUCCESS' || r.status === 'COMPLETED'));
const validationOk = allHealthy;
return [{ json: { ...$json, pack_validation: { child_results_aggregated: childResults, all_children_healthy: allHealthy, validation_ok: validationOk, route_to_error: !validationOk, phase2_acceptance: 'chain_healthy_required' } } }];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    dossier_write: {
      mutation_type: 'namespace_update',
      target: 'dossier.analytics',
      timestamp: new Date().toISOString(),
      writer_id: 'WF-600',
      pack_context: $json.pack_context,
      child_results: $json.pack_validation.child_results_aggregated,
      audit_entry: 'analytics-evolution-pack-completion from WF-600'
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    ...$json,
    se_route_runs_write: {
      operation: 'record_pack_execution',
      pack_id: 'WF-600',
      dossier_id: $json.dossier_id,
      child_workflows_executed: ['CWF-610', 'CWF-620', 'CWF-630'],
      execution_status: 'COMPLETED',
      metrics_collected: $json.pack_validation.metrics_collected,
      loop_closed: $json.pack_validation.loop_closed,
      timestamp: new Date().toISOString()
    }
  }
}];

if ($json.pack_validation.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-600',
    execution_status: 'SUCCESS',
    completion_packet: {
      instance_id: 'WF-600-COMP-' + Date.now(),
      artifact_family: 'analytics_evolution_result',
      schema_version: '1.0.0',
      producer_workflow: 'WF-600',
      dossier_ref: $json.dossier_id,
      created_at: new Date().toISOString(),
      status: 'CREATED',
      payload: {
        pack_executed: 'WF-600',
        metrics_collected: $json.pack_validation.metrics_collected,
        feedback_aggregated: $json.pack_validation.feedback_aggregated,
        signals_synthesized: $json.pack_validation.signals_synthesized,
        loop_closed: $json.pack_validation.loop_closed,
        child_packets: ['CWF-610_output', 'CWF-620_output', 'CWF-630_output']
      }
    }
  }
}];

if (!$json.pack_validation.route_to_error) return [];
return [{
  json: {
    workflow_id: 'WF-600',
    routing_decision: 'ERROR',
    route_to_workflow: 'WF-900',
    error_message: 'Pack validation failed or analytics synthesis failed',
    failure_context: $json.pack_validation,
    child_results: $json.pack_validation.child_results_aggregated
  }
}];
